  ('real-estate-moex-00255', 'real-estate', 'real-estate-moex-112-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '有關公寓大廈公共基金之設置，下列何者錯誤？', '["起造人就公寓大廈領得使用執照一年內之管理維護事項，應按工程造價一定比例或金額提列", "起造人於該公寓大廈使用執照申請時，應提出繳交公庫代收之證明；於公寓大廈召開區分所有 權人會議時，由公庫代為撥付", "公共基金應設專戶儲存，並由管理負責人或管理委員會負責管理", "公共基金經區分所有權人會議決議交付信託者，其運用應依區分所有權人會議之決議為之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:34+00:00", "source_pdf_sha1": "ef2334c92e98", "answer_pdf_sha1": "819236f00ee2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
